118	double nr_cyclic_shift_hopping(uint32_t n_id,
119	                               uint8_t m0,
120	                               uint8_t mcs,
121	                               uint8_t lnormal,
122	                               uint8_t lprime,
123	                               int nr_slot_tx) {
124	  /*
125	   * Implements TS 38.211 subclause 6.3.2.2.2 Cyclic shift hopping
126	   *     - n_id: higher-layer parameter hoppingId
127	   *     - m0: provided by higher layer parameter PUCCH-F0-F1-initial-cyclic-shift of PUCCH-F0-resource-config
128	   *     - mcs: mcs=0 except for PUCCH format 0 when it depends on information to be transmitted according to TS 38.213 subclause 9.2
129	   *     - lnormal: lnormal is the OFDM symbol number in the PUCCH transmission where l=0 corresponds to the first OFDM symbol of the PUCCH transmission
130	   *     - lprime: lprime is the index of the OFDM symbol in the slot that corresponds to the first OFDM symbol of the PUCCH transmission in the slot given by [5, TS 38.213]
131	   */
132	  // alpha_init initialized to 2*PI/12=0.5235987756
133	  double alpha = 0.5235987756;
134	  uint32_t c_init = n_id; // we initialize c_init again to calculate n_cs
135	
136	  uint8_t n_cs=0;
137	  int l = 32, minShift = (14 * 8 * nr_slot_tx) + 8 * (lnormal + lprime);
138	#ifdef DEBUG_NR_PUCCH_TX
139	  printf("\t\t [nr_cyclic_shift_hopping] calculating alpha (cyclic shift) using c_init=%u -> \n",c_init);
140	#endif
141	  uint32_t *seq = gold_cache(c_init, 8 + (minShift + 31) / 32); // TS 38.211 Subclause 5.2.1
142	  int goldIdx = 0;
143	  for (int m=0; m<8; m++) {
144	    while(minShift >= l) {
145	      goldIdx++;
146	      l = l+32;
147	    }
148	    AssertFatal(goldIdx < 8 + (minShift + 31) / 32, "");
149	    int tmpShift = (minShift & ((1 << 5) - 1)); // minShift%32;
150	    minShift ++;
151	    n_cs += (1 << m) * (uint8_t)((seq[goldIdx] >> tmpShift) & 1);
152	    // calculating n_cs (Not sure we have to use nr_slot_tx FIXME!!!)
153	    // n_cs = n_cs+((1<<m)*((uint8_t)((s>>((14*8*nr_slot_tx) + 8*(lnormal+lprime) + m))&1)));
154	  }
155	
156	  alpha = alpha * (double)((m0 + mcs + n_cs) % 12);
157	#ifdef DEBUG_NR_PUCCH_TX
158	  printf("n_cs=%d -> %lf\n",n_cs,alpha);
159	#endif
160	  return(alpha);
161	}

if (PUCCH_GroupHopping == enable) { // PUCCH_GroupHopping 'enabled'
  uint32_t c_init = floor(n_id / 30); // we initialize c_init to calculate u,v according to 6.3.2.2.1 of 38.211
  int l = 32, minShift = (2 * nr_slot_tx + n_hop) << 3;
  uint32_t *seq = gold_cache(c_init, (minShift + 31) / 32 + 8); // TS 38.211 Subclause 5.2.1
  int goldIdx = 0;
  for (int m=0; m<8; m++) {
    while(minShift >= l) {
      goldIdx++;
      l = l+32;
    }
    AssertFatal(goldIdx < 8 + (minShift + 31) / 32, "");
    int tmpShift = (minShift & ((1 << 5) - 1)); // minShift%32;
    f_gh = f_gh + ((1 << m) * ((uint8_t)((seq[goldIdx] >> tmpShift) & 1)));
    minShift ++;
  }

  f_gh = f_gh%30;
  f_ss = n_id % 30;
}

if (PUCCH_GroupHopping == disable) { // PUCCH_GroupHopping 'disabled'

  if (PUCCH_GroupHopping == disable) { // PUCCH_GroupHopping 'disabled'
    uint32_t c_init = (1 << 5) * floor(n_id / 30) + (n_id % 30); // we initialize c_init to calculate u,v
    int goldIdx = 0;
    f_ss = n_id%30;
    int l = 32, minShift = (2 * nr_slot_tx + n_hop);

    while(minShift >= l) {
      goldIdx++;
      l = l+32;
    }
    // TS 38.211 Subclause 5.2.1
    uint32_t *seq = gold_cache(c_init, goldIdx + 1);
    int tmpShift = (minShift & ((1 << 5) - 1)); // minShift%32;
    *v = (uint8_t)((seq[goldIdx] >> tmpShift) & 1);
    //    *v = (uint8_t)((s>>(2*nr_slot_tx+n_hop))&1); // Not sure we have to use nr_slot_tx FIXME!!!
  }

  *u = (f_gh+f_ss)%30;
#ifdef DEBUG_NR_PUCCH_TX
  printf("%d,%d\n",*u,*v);
#endif

if (PUCCH_GroupHopping == neither) { // PUCCH_GroupHopping 'neither'
  f_ss = n_id%30;
}

if (PUCCH_GroupHopping == enable) { // PUCCH_GroupHopping 'enabled'
  uint32_t c_init = n_id / 30; // we initialize c_init to calculate u,v according to 6.3.2.2.1 of 38.211
  int l = 32, minShift = (2 * nr_slot_tx + n_hop) << 3;
  uint32_t *seq = gold_cache(c_init, (minShift + 31) / 32 + 8); // TS 38.211 Subclause 5.2.1
  int goldIdx = 0;
  for (int m=0; m<8; m++) {
    while(minShift >= l) {
      goldIdx++;
      l = l+32;
    }
    AssertFatal(goldIdx < 8 + (minShift + 31) / 32, "");
    int tmpShift = (minShift & ((1 << 5) - 1)); // minShift%32;
    f_gh = f_gh + ((1 << m) * ((uint8_t)((seq[goldIdx] >> tmpShift) & 1)));
    minShift ++;
  }

  f_gh = f_gh%30;
  f_ss = n_id % 30;
}

if (PUCCH_GroupHopping == disable) { // PUCCH_GroupHopping 'disabled'
  uint32_t c_init = (1 << 5) * (n_id / 30) + (n_id % 30); // we initialize c_init to calculate u,v
  int goldIdx = 0;
  f_ss = n_id%30;
  int l = 32, minShift = (2 * nr_slot_tx + n_hop);

  while(minShift >= l) {
    goldIdx++;
    l = l+32;
  }
  // TS 38.211 Subclause 5.2.1
  uint32_t *seq = gold_cache(c_init, goldIdx + 1);
  int tmpShift = (minShift & ((1 << 5) - 1)); // minShift%32;
  *v = (uint8_t)((seq[goldIdx] >> tmpShift) & 1);
  //    *v = (uint8_t)((s>>(2*nr_slot_tx+n_hop))&1); // Not sure we have to use nr_slot_tx FIXME!!!
}

